const config = {
  "previewFeatures": [],
  "clientVersion": "7.5.0",
  "engineVersion": "280c870be64f457428992c43c1f6d557fab6e29e",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================\n// ENUMS\n// ============================================\n\nenum Role {\n  SUPER_ADMIN\n  MANAGER\n  DIRECTEUR\n  DRH\n  DAF\n  DGA\n  DG\n  RESP_PAIE\n}\n\nenum Motif {\n  CREATION\n  REMPLACEMENT\n  RENFORCEMENT\n  NOUVEAU_POSTE\n  EXPANSION\n}\n\nenum TypeContrat {\n  CDI\n  CDD\n  STAGE\n  ALTERNANCE\n  FREELANCE\n}\n\nenum Priorite {\n  HAUTE\n  MOYENNE\n  BASSE\n}\n\nenum StatutDemande {\n  BROUILLON\n  SOUMISE\n  EN_VALIDATION_MANAGER\n  EN_VALIDATION_DIR\n  EN_VALIDATION_DRH\n  EN_VALIDATION_DAF\n  EN_VALIDATION_DGA\n  EN_VALIDATION_DG\n  EN_VALIDATION_CONSEIL\n  VALIDEE\n  REJETEE\n  ANNULEE\n}\n\nenum DecisionEtape {\n  EN_ATTENTE\n  VALIDEE\n  REFUSEE\n  MODIFIEE\n}\n\nenum CircuitType {\n  TECHNICIEN\n  EMPLOYE\n  CADRE_DEBUTANT\n  CADRE_CONFIRME\n  CADRE_SUPERIEUR\n  STRATEGIQUE\n}\n\nenum TypeEntretien {\n  RH // Planifié par le DRH, date libre\n  TECHNIQUE // Manager obligatoire, créneau depuis DisponibiliteInterviewer\n  DIRECTION // Directeur, uniquement pour CADRE_SUPERIEUR et STRATEGIQUE\n}\n\n// ============================================\n// MODÈLE DIRECTION\n// ============================================\n\nmodel Direction {\n  id        String   @id @default(uuid())\n  code      String   @unique\n  nom       String\n  actif     Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users    User[]\n  demandes DemandeRecrutement[]\n\n  @@map(\"directions\")\n}\n\n// ============================================\n// MODÈLE USER\n// ============================================\n\nmodel User {\n  id                 String    @id @default(uuid())\n  email              String    @unique\n  password           String\n  nom                String\n  prenom             String\n  role               Role\n  poste              String?\n  telephone          String?\n  actif              Boolean   @default(true)\n  mustChangePassword Boolean   @default(true)\n  dernierConnexion   DateTime?\n\n  directionId String?\n  direction   Direction? @relation(fields: [directionId], references: [id])\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  demandesCrees   DemandeRecrutement[] @relation(\"CreateurDemandes\")\n  demandesManager DemandeRecrutement[] @relation(\"ManagerDemandes\")\n  validations     ValidationEtape[]\n\n  evaluationsEmploye EvaluationPE[] @relation(\"EmployeEvaluations\")\n  evaluationsManager EvaluationPE[] @relation(\"ManagerEvaluations\")\n  entretiensRealises Entretien[]    @relation(\"InterviewerEntretiens\")\n\n  // ✅ NOUVEAU : disponibilités pour entretiens (MANAGER, DIRECTEUR, DRH)\n  disponibilitesInterviewer DisponibiliteInterviewer[]\n\n  notifications Notification[]\n  auditLogs     AuditLog[]\n\n  @@map(\"users\")\n}\n\n// ============================================\n// MODÈLE CIRCUIT CONFIG\n// ============================================\n\nmodel CircuitConfig {\n  id             String      @id @default(uuid())\n  type           CircuitType @unique\n  nom            String\n  description    String?\n  etapes         Json\n  totalEtapes    Int\n  delaiParDefaut Int         @default(48)\n  actif          Boolean     @default(true)\n  createdAt      DateTime    @default(now())\n  updatedAt      DateTime    @updatedAt\n\n  demandes DemandeRecrutement[]\n\n  @@map(\"circuit_configs\")\n}\n\n// ============================================\n// MODÈLE DEMANDE RECRUTEMENT\n// ============================================\n\nmodel DemandeRecrutement {\n  id            String  @id @default(uuid())\n  reference     String  @unique\n  intitulePoste String\n  description   String?\n  justification String\n\n  motif                Motif\n  commentaireMotif     String?\n  personneRemplaceeNom String?\n  fonctionRemplacee    String?\n\n  typeContrat TypeContrat\n  priorite    Priorite\n\n  budgetMin Decimal? @db.Decimal(10, 2)\n  budgetMax Decimal? @db.Decimal(10, 2)\n\n  dateSouhaitee DateTime\n  statut        StatutDemande @default(BROUILLON)\n\n  niveau CircuitType @default(CADRE_CONFIRME)\n\n  circuitType     CircuitType?\n  totalEtapes     Int?\n  etapeActuelle   Int          @default(0)\n  circuitConfigId String?\n\n  valideeAt DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  createurId String\n  createur   User   @relation(\"CreateurDemandes\", fields: [createurId], references: [id])\n\n  managerId String\n  manager   User   @relation(\"ManagerDemandes\", fields: [managerId], references: [id])\n\n  directionId String?\n  direction   Direction? @relation(fields: [directionId], references: [id])\n\n  circuitConfig  CircuitConfig?    @relation(fields: [circuitConfigId], references: [id])\n  validations    ValidationEtape[]\n  offre          OffreEmploi?\n  disponibilites Disponibilite[]\n\n  // ✅ NOUVEAU : disponibilités des interviewers liées à cette demande\n  disponibilitesInterviewers DisponibiliteInterviewer[]\n\n  @@map(\"demandes\")\n}\n\n// ============================================\n// ✅ NOUVEAU MODÈLE : DISPONIBILITE INTERVIEWER\n// ============================================\n// Stocke les créneaux des interviewers (MANAGER, DIRECTEUR, DRH)\n// liés à une demande de recrutement spécifique.\n// Utilisé par le RH pour planifier les entretiens TECHNIQUE et DIRECTION.\n// Pour l'entretien RH, la date est choisie librement par le DRH.\n\nmodel DisponibiliteInterviewer {\n  id String @id @default(uuid())\n\n  // L'interviewer qui propose ce créneau (MANAGER, DIRECTEUR, DRH)\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  // La demande à laquelle ce créneau est associé\n  demandeId String\n  demande   DemandeRecrutement @relation(fields: [demandeId], references: [id], onDelete: Cascade)\n\n  date       DateTime\n  heureDebut String\n  heureFin   String\n\n  // Passe à true quand un entretien est planifié sur ce créneau\n  reservee Boolean @default(false)\n\n  createdAt DateTime @default(now())\n\n  // Un créneau ne peut être utilisé que pour un seul entretien\n  entretien Entretien?\n\n  @@map(\"disponibilites_interviewers\")\n}\n\n// ============================================\n// MODÈLE VALIDATION ETAPE\n// ============================================\n\nmodel ValidationEtape {\n  id             String             @id @default(uuid())\n  demandeId      String\n  demande        DemandeRecrutement @relation(fields: [demandeId], references: [id], onDelete: Cascade)\n  niveauEtape    Int\n  acteurId       String\n  acteur         User               @relation(fields: [acteurId], references: [id])\n  decision       DecisionEtape      @default(EN_ATTENTE)\n  commentaire    String?\n  dateLimite     DateTime\n  relanceEnvoyee Boolean            @default(false)\n  dateDecision   DateTime?\n\n  createdAt   DateTime     @default(now())\n  relanceJobs RelanceJob[]\n\n  @@map(\"validations_etapes\")\n}\n\n// ============================================\n// MODÈLE RELANCE JOB\n// ============================================\n\nmodel RelanceJob {\n  id                String          @id @default(uuid())\n  validationEtapeId String\n  validationEtape   ValidationEtape @relation(fields: [validationEtapeId], references: [id], onDelete: Cascade)\n  type              String\n  datePrevue        DateTime\n  executee          Boolean         @default(false)\n  executeeAt        DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@map(\"relance_jobs\")\n}\n\n// ============================================\n// MODÈLE DISPONIBILITE (créneaux demande - entretien technique)\n// ============================================\n\nmodel Disponibilite {\n  id         String             @id @default(uuid())\n  demandeId  String\n  demande    DemandeRecrutement @relation(fields: [demandeId], references: [id], onDelete: Cascade)\n  date       DateTime\n  heureDebut String\n  heureFin   String\n\n  @@map(\"disponibilites\")\n}\n\n// ============================================\n// MODÈLE OFFRE EMPLOI\n// ============================================\n\nmodel OffreEmploi {\n  id                  String      @id @default(uuid())\n  reference           String      @unique\n  intitule            String\n  description         String?\n  profilRecherche     String?\n  competences         String[]\n  fourchetteSalariale String?\n  typeContrat         TypeContrat\n  statut              String      @default(\"BROUILLON\")\n\n  datePublication DateTime?\n  lienCandidature String?   @unique\n\n  demandeId    String?             @unique\n  demande      DemandeRecrutement? @relation(fields: [demandeId], references: [id])\n  rhId         String\n  candidatures Candidature[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"offres\")\n}\n\n// ============================================\n// MODÈLE CANDIDATURE\n// ============================================\n\nmodel Candidature {\n  id                    String   @id @default(uuid())\n  reference             String   @unique\n  nom                   String\n  prenom                String\n  email                 String\n  telephone             String?\n  cvUrl                 String\n  cvTexte               String?\n  scoreGlobal           Int?\n  scoreExp              Int?\n  competencesDetectees  String[]\n  competencesManquantes String[]\n  statut                String   @default(\"NOUVELLE\")\n  consentementRGPD      Boolean  @default(false)\n  consentementIA        Boolean  @default(false)\n  dateSoumission        DateTime @default(now())\n\n  offreId    String? // ✅ AJOUTER ? pour rendre optionnel\n  offre      OffreEmploi? @relation(fields: [offreId], references: [id]) // ✅ AJOUTER ?\n  entretiens Entretien[]\n  contrat    Contrat?\n\n  @@map(\"candidatures\")\n}\n\n// ============================================\n// MODÈLE ENTRETIEN — CORRIGÉ\n// ============================================\n\nmodel Entretien {\n  id String @id @default(uuid())\n\n  // ✅ Enum TypeEntretien (RH | TECHNIQUE | DIRECTION)\n  type TypeEntretien\n\n  date       DateTime\n  heure      String\n  lieu       String\n  statut     String   @default(\"PLANIFIE\")\n  feedback   String?\n  evaluation Int?\n\n  candidatureId String\n  candidature   Candidature @relation(fields: [candidatureId], references: [id])\n\n  // Pour RH : interviewerId = DRH lui-même\n  // Pour TECHNIQUE : interviewerId = MANAGER de la direction\n  // Pour DIRECTION : interviewerId = DIRECTEUR\n  interviewerId String\n  interviewer   User   @relation(\"InterviewerEntretiens\", fields: [interviewerId], references: [id])\n\n  // ✅ NOUVEAU : créneau utilisé (null pour entretien RH — date libre)\n  // Pour TECHNIQUE et DIRECTION : obligatoirement un créneau DisponibiliteInterviewer\n  disponibiliteId String?                   @unique\n  disponibilite   DisponibiliteInterviewer? @relation(fields: [disponibiliteId], references: [id])\n\n  @@map(\"entretiens\")\n}\n\n// ============================================\n// MODÈLE CONTRAT\n// ============================================\n\nmodel Contrat {\n  id          String      @id @default(uuid())\n  reference   String      @unique\n  typeContrat TypeContrat\n  salaire     String\n  dateDebut   DateTime\n  dateFin     DateTime?\n  statut      String      @default(\"BROUILLON\")\n  pdfUrl      String?\n\n  candidatureId String        @unique\n  candidature   Candidature   @relation(fields: [candidatureId], references: [id])\n  evaluationPE  EvaluationPE?\n  avenants      Avenant[]\n\n  @@map(\"contrats\")\n}\n\n// ============================================\n// MODÈLE EVALUATION PE\n// ============================================\n\nmodel EvaluationPE {\n  id                 String   @id @default(uuid())\n  dateDebut          DateTime\n  dateFin            DateTime\n  joursRestants      Int\n  decision           String?\n  commentaire        String?\n  commentaireManager String?\n  etapeActuelle      Int\n\n  employeId String\n  employe   User    @relation(\"EmployeEvaluations\", fields: [employeId], references: [id])\n  managerId String\n  manager   User    @relation(\"ManagerEvaluations\", fields: [managerId], references: [id])\n  contratId String  @unique\n  contrat   Contrat @relation(fields: [contratId], references: [id])\n\n  @@map(\"evaluations_pe\")\n}\n\n// ============================================\n// MODÈLE AVENANT\n// ============================================\n\nmodel Avenant {\n  id          String   @id @default(uuid())\n  typeAvenant String\n  date        DateTime\n  description String\n\n  contratId String\n  contrat   Contrat @relation(fields: [contratId], references: [id])\n\n  @@map(\"avenants\")\n}\n\n// ============================================\n// MODÈLE NOTIFICATION\n// ============================================\n\nmodel Notification {\n  id         String    @id @default(uuid())\n  type       String\n  titre      String\n  message    String\n  lienAction String?\n  lu         Boolean   @default(false)\n  luAt       DateTime?\n\n  destinataireId String\n  destinataire   User    @relation(fields: [destinataireId], references: [id])\n  entityType     String?\n  entityId       String?\n\n  createdAt DateTime @default(now())\n\n  @@map(\"notifications\")\n}\n\n// ============================================\n// MODÈLE AUDIT LOG\n// ============================================\n\nmodel AuditLog {\n  id               String  @id @default(uuid())\n  action           String\n  entityType       String\n  entityId         String\n  anciennesValeurs Json?\n  nouvellesValeurs Json?\n  ipAdresse        String?\n  userAgent        String?\n  details          String?\n\n  acteurId String\n  acteur   User   @relation(fields: [acteurId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@map(\"audit_logs\")\n}\n"
}

